v = latestOf(series[0]);
level = (v===null)?'nodata':(v>1300?'critical':(v>=1200?'warning':'normal'));
counts[level]++;
(function(){ var e=svgnode.getElementById('furnace_1_value'); if(e) e.textContent = fmt(v, 1); })();
setDot('furnace_1_status_dot', COLOR[level]);
(function(){
  var g = svgnode.getElementById('furnace_1_glow');
  if (g && v !== null) {
    var op = Math.max(0, Math.min(1, (v - 1000) / 400));
